targets.expr:
sum by (envoy_http_conn_manager_prefix) (rate(
    envoy_http_rs_too_large{node=~"^${t2}$", envoy_http_conn_manager_prefix =~ "${app}"}[$__rate_interval]
) 
* on (node) group_left() (
    kube_node_labels{label_service_cilium_io_node=~"t2"}
))

sum by (instance) (
    rate(
        node_network_receive_bytes_total[$__rate_interval])
    ) * on (instance) group_left(node) (
        label_replace(kube_node_status_addresses{node=~"$t2"}, "instance", "$1:9100", "address", "(.*)"
    )
) * on (node) (
    kube_node_labels{label_service_cilium_io_node="t2"}
)

sum by (instance) (
    rate(
        node_network_receive_packets_total{device="eth0"}[$__rate_interval])
    ) * on (instance) group_left(node) (
        label_replace(kube_node_status_addresses{node=~"$t2"}, "instance", "$1:9100", "address", "(.*)"
    )
) * on (node) (
    kube_node_labels{label_service_cilium_io_node="t2"}
)

100 * avg(
  1 - rate(
    node_cpu_seconds_total{mode=~"idle"}[$__rate_interval]
    )
  ) by (instance)
* on (instance) group_left(node) (
  label_replace(kube_node_status_addresses{node=~"^${t2}$"}, "instance", "$1:9100", "address", "(.*)")
)
* on (node) group_left() (
  kube_node_labels{label_service_cilium_io_node=~"t2"}
)

node_load5{job="node-exporter"} *  on (instance) group_left(node) (label_replace(kube_node_status_addresses{type="InternalIP", node=~"$t2"}, "instance", "$1:9100", "address", "(.*)"))
* on (node) group_left() (
  kube_node_labels{label_service_cilium_io_node=~"t2"}
)

node_load15{job="node-exporter"} *  on (instance) group_left(node) (label_replace(kube_node_status_addresses{type="InternalIP", node=~"$t2"}, "instance", "$1:9100", "address", "(.*)"))
* on (node) group_left() (
  kube_node_labels{label_service_cilium_io_node=~"t2"}
)
